import{_ as t,o as e,c as o,ag as i}from"./chunks/framework.DUza98OV.js";const c=JSON.parse('{"title":"Git 高效协作","description":"","frontmatter":{},"headers":[],"relativePath":"tools/git-workflow.md","filePath":"tools/git-workflow.md","lastUpdated":1776563785000}'),r={name:"tools/git-workflow.md"};function l(n,a,s,d,h,p){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="git-高效协作" tabindex="-1">Git 高效协作 <a class="header-anchor" href="#git-高效协作" aria-label="Permalink to &quot;Git 高效协作&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>多人协作开发时，为什么经常会遇到提交混乱、分支冲突和回滚困难的问题？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>Git 协作混乱通常不是工具问题，而是流程缺失。团队应该明确分支模型、提交规范和合并策略，例如功能开发走 feature 分支，发布走 main 分支，修复线上问题走 hotfix 分支。提交信息保持语义化后，回溯问题和生成变更记录都会更顺畅。</p><p>另外，频繁小步提交和及时同步主干可以显著降低冲突成本。相比堆积大量改动后一次性合并，这种方式更容易定位问题，也更适合代码评审。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>分支模型要和团队节奏匹配。</li><li>提交信息建议语义化，便于追踪与回滚。</li><li>小步提交、频繁同步能降低冲突。</li><li>合并前的自测和代码评审不可省略。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>高效 Git 协作依赖清晰流程和稳定习惯。工具本身很强大，但真正决定团队效率的是使用方式。</p>',10)])])}const u=t(r,[["render",l]]);export{c as __pageData,u as default};
